mapper.select:
SELECT fi.region, COUNT(pp.id) AS totalCount, SUM(CASE WHEN pp.inspect_result = '合格' THEN 1 ELSE 0 END) AS passCount, ROUND( SUM(CASE WHEN pp.inspect_result = '合格' THEN 1 ELSE 0 END) * 100.0 / COUNT(pp.id), 1 ) AS passRate FROM peanut_product pp LEFT JOIN farmer_info fi ON pp.farmer_id = fi.farmer_id WHERE pp.is_deleted = 0
AND fi.region = #{region}
GROUP BY fi.region ORDER BY passRate DESC
